.container {
  display: flex;
  flex-direction: row;       /* row, column, row-reverse */
  justify-content: center;   /* মূল অক্ষ বরাবর সাজানো */
  align-items: center;       /* ক্রস অক্ষ বরাবর সাজানো */
  gap: 16px;                 /* আইটেমের মধ্যে ফাঁকা জায়গা */
}

.item {
  flex-grow: 1;     /* অতিরিক্ত জায়গা পেলে কতটা বাড়বে */
  flex-shrink: 1;   /* জায়গা কম হলে কতটা ছোট হবে */
  flex-basis: 200px;/* শুরুর সাইজ */
  flex: 1;          /* শর্টহ্যান্ড: grow shrink basis */
}

nav ul {
  display: flex;
  justify-content: space-between;
  align-items: center;
  list-style: none;
}
